.darma-loader-darma-custom-240 {
  color: var(--loader-color, #9333ea);
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  animation: darma-loader-darma-custom-240-l1 .8s infinite linear;
}
@keyframes darma-loader-darma-custom-240-l1{
  to {background-position: 25% 0,37.5% 100%}
}

